## Description

```
"""
ML env check v4: блоки тестов + задачи. БЕЗ предобученных весов.

Все модели создаются с нуля (random init / spacy.blank / Word2Vec на мини-корпусе).
Нет prefetch, нет ./tmp_models, нет скачиваний. Тесты проверяют только
работоспособность кода и пайплайнов.

Везде где обучение/валидация: 10 train + 10 test, 3 эпохи.
"""
import importlib
import sys
import time
import platform
import warnings
import json
import os
warnings.filterwarnings("ignore")


# ====================================================================
# Инфраструктура
# ====================================================================
def section(title):
    print("\n" + "=" * 72)
    print(f"  {title}")
    print("=" * 72)


def subsection(title):
    print(f"\n--- {title} ---")


def ok(msg):   print(f"  [OK]   {msg}")
def fail(msg): print(f"  [FAIL] {msg}")


results = {"env": {}, "tests": {}}


def run_test(block, lib, test_name, fn, description):
    t0 = time.time()
    try:
        out = fn() or {}
        dt = time.time() - t0
        results["tests"].setdefault(block, {}).setdefault(lib, {})[test_name] = {
            "status": "ok", "time_s": round(dt, 3),
            "description": description, **out,
        }
        ok(f"[{block}] {lib:<12} :: {test_name:<26} ({dt*1000:>5.0f} ms)  {description}")
        return True, out
    except Exception as e:
        dt = time.time() - t0
        err = f"{type(e).__name__}: {str(e)[:200]}"
        results["tests"].setdefault(block, {}).setdefault(lib, {})[test_name] = {
            "status": "fail", "time_s": round(dt, 3),
            "description": description, "error": err,
        }
        fail(f"[{block}] {lib:<12} :: {test_name:<26} {err[:110]}")
        return False, None


def get_test(block, lib, test_name):
    return results["tests"].get(block, {}).get(lib, {}).get(test_name)


# ====================================================================
# Блок 0: версии и GPU
# ====================================================================
section("Блок 0: Окружение")

print(f"Python:   {sys.version.split()[0]}")
print(f"Platform: {platform.platform()}")

LIBS = [
    "numpy", "pandas", "polars", "scipy",
    "PIL", "cv2",
    "sklearn",
    "xgboost", "lightgbm", "catboost",
    "torch", "torchvision",
    "transformers", "peft", "accelerate", "datasets",
    "huggingface_hub", "sentence_transformers",
    "spacy", "nltk", "gensim", "fasttext",
    "librosa", "imageio",
    "tqdm", "matplotlib", "pyarrow",
]
versions = {}
print()
for name in LIBS:
    try:
        mod = importlib.import_module(name)
        ver = getattr(mod, "__version__", "?")
        versions[name] = ver
        print(f"  {name:<22} {ver}")
    except ImportError:
        versions[name] = None
        print(f"  {name:<22} НЕ УСТАНОВЛЕН")

versions["sklearn-gb"] = versions.get("sklearn")
results["env"]["versions"] = versions

print()
try:
    import torch
    if torch.cuda.is_available():
        p = torch.cuda.get_device_properties(0)
        print(f"  GPU: {p.name}  |  {p.total_memory/1024**3:.1f} GB  |  "
              f"SM {p.major}.{p.minor}  |  bf16={torch.cuda.is_bf16_supported()}")
        results["env"]["gpu"] = {
            "name": p.name, "mem_gb": round(p.total_memory/1024**3, 1),
            "sm": f"{p.major}.{p.minor}",
            "bf16": torch.cuda.is_bf16_supported(),
        }
    else:
        results["env"]["gpu"] = None
        print("  GPU: недоступна")
except Exception as e:
    print(f"  GPU info: {e}")


# ====================================================================
# Блок 1: DATA — numpy, pandas, polars, scipy
# ====================================================================
section("Блок 1: DATA (numpy / pandas / polars / scipy)")

import numpy as np
RNG = np.random.RandomState(42)

# --------- numpy ---------
subsection("numpy")

def np_matmul():
    a = RNG.randn(200, 200).astype(np.float32)
    c = a @ a.T
    return {"shape": list(c.shape)}

def np_broadcast_agg():
    a = RNG.randn(100, 20)
    centered = a - a.mean(axis=0, keepdims=True)
    return {"max_abs_after_center": round(float(np.abs(centered).max()), 3)}

def np_linalg():
    A = RNG.randn(50, 50)
    U, S, Vt = np.linalg.svd(A)
    err = float(np.abs(A - (U * S) @ Vt).max())
    b = RNG.randn(50)
    x = np.linalg.solve(A, b)
    return {"svd_reconstruct_err": round(err, 6),
            "solve_residual": round(float(np.abs(A @ x - b).max()), 6)}

run_test("data", "numpy", "matmul",        np_matmul,        "matmul 200x200 float32")
run_test("data", "numpy", "broadcast_agg", np_broadcast_agg, "broadcasting + агрегации по осям")
run_test("data", "numpy", "linalg",        np_linalg,        "SVD и solve для СЛАУ 50x50")

# --------- pandas ---------
subsection("pandas")

def pd_create_and_types():
    import pandas as pd
    df = pd.DataFrame({
        "int_col":   np.arange(100),
        "float_col": RNG.randn(100),
        "cat_col":   pd.Categorical(np.tile(["A", "B", "C", "D"], 25)),
        "date_col":  pd.date_range("2024-01-01", periods=100, freq="D"),
        "str_col":   [f"row_{i}" for i in range(100)],
    })
    return {"shape": list(df.shape)}

def pd_groupby():
    import pandas as pd
    df = pd.DataFrame({"g": np.tile(["A", "B", "C", "D"], 25),
                       "x": RNG.randn(100), "y": RNG.randn(100)})
    agg = df.groupby("g").agg(x_mean=("x", "mean"), x_std=("x", "std"),
                              y_sum=("y", "sum"), n=("x", "count"))
    return {"n_groups": int(len(agg))}

def pd_merge():
    import pandas as pd
    left  = pd.DataFrame({"id": range(50), "val_l": RNG.randn(50)})
    right = pd.DataFrame({"id": range(25, 75), "val_r": RNG.randn(50)})
    return {"inner": int(len(left.merge(right, on="id", how="inner"))),
            "outer": int(len(left.merge(right, on="id", how="outer")))}

def pd_timeseries():
    import pandas as pd
    idx = pd.date_range("2024-01-01", periods=100, freq="h")
    s = pd.Series(RNG.randn(100), index=idx)
    daily = s.resample("D").mean()
    rolled = s.rolling(window=5).mean().dropna()
    return {"hourly_n": int(len(s)), "daily_n": int(len(daily)),
            "rolled_n": int(len(rolled))}

def pd_io_csv():
    import pandas as pd
    df = pd.DataFrame({"a": range(50), "b": RNG.randn(50)})
    df.to_csv("/tmp/_pd.csv", index=False)
    loaded = pd.read_csv("/tmp/_pd.csv")
    return {"rows": int(len(loaded))}

def pd_io_parquet():
    import pandas as pd
    df = pd.DataFrame({"a": range(50), "b": RNG.randn(50)})
    df.to_parquet("/tmp/_pd.parquet")
    loaded = pd.read_parquet("/tmp/_pd.parquet")
    return {"rows": int(len(loaded))}

run_test("data", "pandas", "create_and_types", pd_create_and_types, "DataFrame с разными dtypes")
run_test("data", "pandas", "groupby",          pd_groupby,          "groupby + named aggregations")
run_test("data", "pandas", "merge",            pd_merge,            "merge inner и outer")
run_test("data", "pandas", "timeseries",       pd_timeseries,       "resample + rolling для временных рядов")
run_test("data", "pandas", "io_csv",           pd_io_csv,           "round-trip через CSV")
run_test("data", "pandas", "io_parquet",       pd_io_parquet,       "round-trip через Parquet (pyarrow)")

# --------- polars ---------
subsection("polars")

def pl_import():
    import polars as pl
    return {"version": pl.__version__}

def pl_create():
    import polars as pl
    df = pl.DataFrame({"g": ["A", "B", "C", "D"] * 25,
                       "x": RNG.randn(100).tolist(),
                       "y": RNG.randn(100).tolist()})
    return {"shape": list(df.shape)}

def pl_group_by():
    import polars as pl
    df = pl.DataFrame({"g": ["A", "B", "C", "D"] * 25,
                       "x": RNG.randn(100).tolist()})
    agg = df.group_by("g").agg(pl.col("x").mean().alias("x_mean"),
                                pl.col("x").std().alias("x_std"),
                                pl.len().alias("n"))
    return {"n_groups": int(len(agg))}

def pl_lazy():
    import polars as pl
    df = pl.DataFrame({"g": ["A", "B"] * 50, "x": RNG.randn(100).tolist()})
    result = (df.lazy()
                .filter(pl.col("x") > 0)
                .group_by("g")
                .agg(pl.col("x").mean().alias("mean_pos"))
                .sort("g")
                .collect())
    return {"rows": int(len(result))}

def pl_join():
    import polars as pl
    left  = pl.DataFrame({"id": list(range(50)),     "val_l": RNG.randn(50).tolist()})
    right = pl.DataFrame({"id": list(range(25, 75)), "val_r": RNG.randn(50).tolist()})
    return {"rows": int(len(left.join(right, on="id", how="inner")))}

polars_ok, _ = run_test("data", "polars", "import", pl_import, "импорт и версия")
if polars_ok:
    run_test("data", "polars", "create",        pl_create,   "создание DataFrame")
    run_test("data", "polars", "group_by",      pl_group_by, "group_by с агрегациями")
    run_test("data", "polars", "lazy_pipeline", pl_lazy,     "lazy: filter→group_by→sort→collect")
    run_test("data", "polars", "join",          pl_join,     "inner join")

# --------- scipy ---------
subsection("scipy")

def sp_stats():
    from scipy import stats
    a = RNG.randn(100); b = RNG.randn(100) + 0.3
    _, p_val = stats.ttest_ind(a, b)
    rho, _ = stats.spearmanr(a, b)
    return {"ttest_p": round(float(p_val), 4), "spearman_rho": round(float(rho), 4)}

def sp_sparse():
    from scipy import sparse
    m = sparse.random(100, 100, density=0.1, format="csr", random_state=42)
    prod = m @ m.T
    return {"nnz_in": int(m.nnz), "nnz_out": int(prod.nnz)}

def sp_optimize():
    from scipy.optimize import minimize
    def f(v): return (v[0] - 3) ** 2 + (v[1] + 1) ** 2
    res = minimize(f, x0=[0.0, 0.0])
    return {"x_star": [round(float(x), 3) for x in res.x], "converged": bool(res.success)}

def sp_interp():
    from scipy import interpolate
    x = np.linspace(0, 10, 20); y = np.sin(x)
    f = interpolate.interp1d(x, y, kind="cubic")
    return {"out_shape": list(f(np.linspace(0, 10, 100)).shape)}

run_test("data", "scipy", "stats",       sp_stats,    "t-test и Spearman")
run_test("data", "scipy", "sparse",      sp_sparse,   "sparse CSR matrix + matmul")
run_test("data", "scipy", "optimize",    sp_optimize, "minimize на квадратичной функции")
run_test("data", "scipy", "interpolate", sp_interp,   "cubic interpolation 1D")


# ====================================================================
# Блок 2: BOOSTING
# ====================================================================
section("Блок 2: BOOSTING (10 фич, 10 train + 10 val, 10 деревьев)")

from sklearn.metrics import accuracy_score, mean_squared_error

N_FEATURES, N_TRAIN, N_VAL = 10, 10, 10
N_ESTIMATORS, MAX_DEPTH = 10, 3

X_cls_tr  = RNG.randn(N_TRAIN, N_FEATURES)
y_cls_tr  = (X_cls_tr[:, 0] + X_cls_tr[:, 1] > 0).astype(int)
X_cls_val = RNG.randn(N_VAL, N_FEATURES)
y_cls_val = (X_cls_val[:, 0] + X_cls_val[:, 1] > 0).astype(int)

X_reg_tr  = RNG.randn(N_TRAIN, N_FEATURES)
y_reg_tr  = X_reg_tr[:, 0] * 2 + X_reg_tr[:, 1] + RNG.randn(N_TRAIN) * 0.1
X_reg_val = RNG.randn(N_VAL, N_FEATURES)
y_reg_val = X_reg_val[:, 0] * 2 + X_reg_val[:, 1] + RNG.randn(N_VAL) * 0.1

def _acc(m, X, y): return round(float(accuracy_score(y, m.predict(X))), 4)
def _mse(m, X, y): return round(float(mean_squared_error(y, m.predict(X))), 4)

# XGBoost
try:
    import xgboost as xgb
    def _xgb_cls(dev):
        m = xgb.XGBClassifier(n_estimators=N_ESTIMATORS, max_depth=MAX_DEPTH,
                              device=dev, verbosity=0, eval_metric="logloss")
        m.fit(X_cls_tr, y_cls_tr); return {"acc": _acc(m, X_cls_val, y_cls_val)}
    def _xgb_reg(dev):
        m = xgb.XGBRegressor(n_estimators=N_ESTIMATORS, max_depth=MAX_DEPTH,
                             device=dev, verbosity=0)
        m.fit(X_reg_tr, y_reg_tr); return {"mse": _mse(m, X_reg_val, y_reg_val)}
    run_test("boosting", "xgboost", "cls_cpu", lambda: _xgb_cls("cpu"),  "классификация на CPU")
    run_test("boosting", "xgboost", "cls_gpu", lambda: _xgb_cls("cuda"), "классификация на CUDA GPU")
    run_test("boosting", "xgboost", "reg_cpu", lambda: _xgb_reg("cpu"),  "регрессия на CPU")
    run_test("boosting", "xgboost", "reg_gpu", lambda: _xgb_reg("cuda"), "регрессия на CUDA GPU")
except ImportError:
    fail("xgboost не установлен")

# LightGBM
try:
    import lightgbm as lgb
    LGB = dict(n_estimators=N_ESTIMATORS, max_depth=MAX_DEPTH,
               num_leaves=4, min_data_in_leaf=1, min_data_in_bin=1, verbose=-1)
    def _lgb_cls():
        m = lgb.LGBMClassifier(device="cpu", **LGB)
        m.fit(X_cls_tr, y_cls_tr); return {"acc": _acc(m, X_cls_val, y_cls_val)}
    def _lgb_reg():
        m = lgb.LGBMRegressor(device="cpu", **LGB)
        m.fit(X_reg_tr, y_reg_tr); return {"mse": _mse(m, X_reg_val, y_reg_val)}
    run_test("boosting", "lightgbm", "cls_cpu", _lgb_cls, "классификация на CPU")
    run_test("boosting", "lightgbm", "reg_cpu", _lgb_reg, "регрессия на CPU")
except ImportError:
    fail("lightgbm не установлен")

# CatBoost
try:
    import catboost as cb
    def _cb_cls(tt):
        m = cb.CatBoostClassifier(iterations=N_ESTIMATORS, depth=MAX_DEPTH,
                                  task_type=tt, devices="0" if tt == "GPU" else None,
                                  verbose=False, allow_writing_files=False)
        m.fit(X_cls_tr, y_cls_tr); return {"acc": _acc(m, X_cls_val, y_cls_val)}
    def _cb_reg(tt):
        m = cb.CatBoostRegressor(iterations=N_ESTIMATORS, depth=MAX_DEPTH,
                                 task_type=tt, devices="0" if tt == "GPU" else None,
                                 verbose=False, allow_writing_files=False)
        m.fit(X_reg_tr, y_reg_tr); return {"mse": _mse(m, X_reg_val, y_reg_val)}
    run_test("boosting", "catboost", "cls_cpu", lambda: _cb_cls("CPU"), "классификация на CPU")
    run_test("boosting", "catboost", "cls_gpu", lambda: _cb_cls("GPU"), "классификация на CUDA GPU")
    run_test("boosting", "catboost", "reg_cpu", lambda: _cb_reg("CPU"), "регрессия на CPU")
    run_test("boosting", "catboost", "reg_gpu", lambda: _cb_reg("GPU"), "регрессия на CUDA GPU")
except ImportError:
    fail("catboost не установлен")

# sklearn-gb
try:
    from sklearn.ensemble import (
        GradientBoostingClassifier, GradientBoostingRegressor,
        HistGradientBoostingClassifier, HistGradientBoostingRegressor,
    )
    def _skgb_cls():
        m = GradientBoostingClassifier(n_estimators=N_ESTIMATORS, max_depth=MAX_DEPTH, random_state=0)
        m.fit(X_cls_tr, y_cls_tr); return {"acc": _acc(m, X_cls_val, y_cls_val)}
    def _skgb_reg():
        m = GradientBoostingRegressor(n_estimators=N_ESTIMATORS, max_depth=MAX_DEPTH, random_state=0)
        m.fit(X_reg_tr, y_reg_tr); return {"mse": _mse(m, X_reg_val, y_reg_val)}
    def _skhgb_cls():
        m = HistGradientBoostingClassifier(max_iter=N_ESTIMATORS, max_depth=MAX_DEPTH,
                                           min_samples_leaf=1, random_state=0)
        m.fit(X_cls_tr, y_cls_tr); return {"acc": _acc(m, X_cls_val, y_cls_val)}
    def _skhgb_reg():
        m = HistGradientBoostingRegressor(max_iter=N_ESTIMATORS, max_depth=MAX_DEPTH,
                                          min_samples_leaf=1, random_state=0)
        m.fit(X_reg_tr, y_reg_tr); return {"mse": _mse(m, X_reg_val, y_reg_val)}
    run_test("boosting", "sklearn-gb", "cls_cpu",      _skgb_cls,  "GradientBoostingClassifier CPU")
    run_test("boosting", "sklearn-gb", "reg_cpu",      _skgb_reg,  "GradientBoostingRegressor CPU")
    run_test("boosting", "sklearn-gb", "hist_cls_cpu", _skhgb_cls, "HistGradientBoostingClassifier CPU")
    run_test("boosting", "sklearn-gb", "hist_reg_cpu", _skhgb_reg, "HistGradientBoostingRegressor CPU")
except ImportError:
    fail("sklearn не установлен")


# ====================================================================
# Блок 3: CV
# ====================================================================
section("Блок 3: CV (opencv / pillow / imageio / torchvision)")

# --------- opencv ---------
subsection("opencv")
try:
    import cv2

    def cv_generate_and_save():
        img = np.zeros((256, 256, 3), dtype=np.uint8)
        cv2.rectangle(img, (50, 50), (150, 150), (0, 255, 0), 2)
        cv2.circle(img, (180, 180), 40, (0, 0, 255), -1)
        cv2.imwrite("/tmp/_cv_test.png", img)
        return {"shape": list(img.shape)}

    def cv_read():
        img = cv2.imread("/tmp/_cv_test.png")
        if img is None: raise RuntimeError("imread вернул None")
        return {"shape": list(img.shape)}

    def cv_color():
        img = cv2.imread("/tmp/_cv_test.png")
        return {"gray": list(cv2.cvtColor(img, cv2.COLOR_BGR2GRAY).shape),
                "hsv":  list(cv2.cvtColor(img, cv2.COLOR_BGR2HSV).shape)}

    def cv_filters():
        img = cv2.imread("/tmp/_cv_test.png")
        gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
        return {
            "gaussian": list(cv2.GaussianBlur(img, (5, 5), 1.0).shape),
            "median":   list(cv2.medianBlur(img, 5).shape),
            "bilateral":list(cv2.bilateralFilter(img, 9, 75, 75).shape),
            "sobel":    list(cv2.Sobel(gray, cv2.CV_64F, 1, 0, ksize=3).shape),
            "canny":    list(cv2.Canny(gray, 100, 200).shape),
        }

    def cv_morphology():
        img = cv2.imread("/tmp/_cv_test.png", cv2.IMREAD_GRAYSCALE)
        k = np.ones((3, 3), np.uint8)
        return {"erode":  list(cv2.erode(img, k).shape),
                "dilate": list(cv2.dilate(img, k).shape),
                "open":   list(cv2.morphologyEx(img, cv2.MORPH_OPEN, k).shape)}

    def cv_geometric():
        img = cv2.imread("/tmp/_cv_test.png")
        h, w = img.shape[:2]
        M = cv2.getRotationMatrix2D((w/2, h/2), 45, 1.0)
        return {"resize": list(cv2.resize(img, (128, 128)).shape),
                "rotate": list(cv2.warpAffine(img, M, (w, h)).shape),
                "flip":   list(cv2.flip(img, 1).shape)}

    run_test("cv", "cv2", "generate_and_save", cv_generate_and_save, "создание 256x256 + imwrite")
    run_test("cv", "cv2", "read",               cv_read,              "imread")
    run_test("cv", "cv2", "color_convert",      cv_color,             "BGR→Gray/HSV")
    run_test("cv", "cv2", "filters",            cv_filters,           "Gaussian/median/bilateral/Sobel/Canny")
    run_test("cv", "cv2", "morphology",         cv_morphology,        "erode/dilate/opening")
    run_test("cv", "cv2", "geometric",          cv_geometric,         "resize/rotate/flip")
except ImportError:
    fail("cv2 не установлен (нужен opencv-python-headless)")

# --------- Pillow ---------
subsection("Pillow")
try:
    from PIL import Image, ImageFilter, ImageEnhance, ImageOps

    def pil_save():
        arr = (RNG.rand(256, 256, 3) * 255).astype(np.uint8)
        img = Image.fromarray(arr)
        img.save("/tmp/_pil_test.png")
        img.save("/tmp/_pil_test.jpg", quality=90)
        return {"size": list(img.size)}

    def pil_convert():
        img = Image.open("/tmp/_pil_test.png")
        return {"L": img.convert("L").mode, "RGBA": img.convert("RGBA").mode}

    def pil_geom():
        img = Image.open("/tmp/_pil_test.png")
        return {"resized": list(img.resize((128, 128)).size),
                "cropped": list(img.crop((50, 50, 200, 200)).size),
                "rotated": list(img.rotate(45).size)}

    def pil_filters():
        img = Image.open("/tmp/_pil_test.png")
        return {
            "blur":     list(img.filter(ImageFilter.BLUR).size),
            "sharpen":  list(img.filter(ImageFilter.SHARPEN).size),
            "edges":    list(img.filter(ImageFilter.FIND_EDGES).size),
            "gaussian": list(img.filter(ImageFilter.GaussianBlur(2)).size),
        }

    def pil_enhance():
        img = Image.open("/tmp/_pil_test.png")
        return {"brightness": list(ImageEnhance.Brightness(img).enhance(1.5).size),
                "contrast":   list(ImageEnhance.Contrast(img).enhance(1.3).size),
                "equalize":   list(ImageOps.equalize(img.convert("RGB")).size)}

    run_test("cv", "PIL", "save",     pil_save,     "создание и сохранение PNG+JPEG")
    run_test("cv", "PIL", "convert",  pil_convert,  "convert в L и RGBA")
    run_test("cv", "PIL", "geometric", pil_geom,    "resize/crop/rotate")
    run_test("cv", "PIL", "filters",   pil_filters, "BLUR/SHARPEN/FIND_EDGES/GaussianBlur")
    run_test("cv", "PIL", "enhance",   pil_enhance, "Brightness/Contrast/equalize")
except ImportError:
    fail("PIL не установлен")

# --------- imageio (создание GIF) ---------
subsection("imageio")
try:
    import imageio.v3 as iio

    GIF_PATH = "/tmp/_test.gif"

    def imageio_create_gif():
        frames = []
        for i in range(10):
            frame = np.zeros((64, 64, 3), dtype=np.uint8)
            frame[:, :, 2] = 40
            x = 5 + i * 5
            y = 5 + i * 5
            frame[y:y+15, x:x+15] = [255, 180, 0]
            frames.append(frame)
        iio.imwrite(GIF_PATH, frames, duration=100, loop=0)
        return {"path": GIF_PATH,
                "n_frames_written": len(frames),
                "frame_shape": list(frames[0].shape),
                "file_size_bytes": os.path.getsize(GIF_PATH)}

    def imageio_read_gif():
        frames = iio.imread(GIF_PATH, index=None)
        n_frames = frames.shape[0] if frames.ndim == 4 else 1
        return {"n_frames_read": int(n_frames),
                "shape": list(frames.shape),
                "dtype": str(frames.dtype)}

    def imageio_iter():
        n = 0; first_shape = None
        for frame in iio.imiter(GIF_PATH):
            if first_shape is None: first_shape = list(frame.shape)
            n += 1
        return {"n_frames_iterated": n, "first_frame_shape": first_shape}

    run_test("cv", "imageio", "create_gif",  imageio_create_gif, "GIF из 10 кадров с движущимся квадратом")
    run_test("cv", "imageio", "read_gif",    imageio_read_gif,   "чтение GIF целиком через imread")
    run_test("cv", "imageio", "iter_frames", imageio_iter,       "покадровое чтение через imiter")
except ImportError:
