    def make_seg_data(n, size=256, seed=0):
        g = torch.Generator().manual_seed(seed)
        imgs = torch.rand(n, 3, size, size, generator=g) * 0.3
        masks = torch.zeros(n, size, size, dtype=torch.long)
        yy, xx = torch.meshgrid(torch.arange(size), torch.arange(size), indexing="ij")
        for i in range(n):
            cx = torch.randint(60, size-60, (1,), generator=g).item()
            cy = torch.randint(60, size-60, (1,), generator=g).item()
            r  = torch.randint(30, 55, (1,), generator=g).item()
            circle = ((xx - cx)**2 + (yy - cy)**2) <= r**2
            masks[i][circle] = 1
            imgs[i, 0][circle] += 0.6
        imgs = imgs.clamp(0, 1)
        mean = torch.tensor([0.485, 0.456, 0.406]).view(1, 3, 1, 1)
        std  = torch.tensor([0.229, 0.224, 0.225]).view(1, 3, 1, 1)
        imgs = (imgs - mean) / std
        return imgs, masks

    X_seg_tr,  M_seg_tr  = make_seg_data(10, 256, seed=10)
    X_seg_val, M_seg_val = make_seg_data(10, 256, seed=20)
    NUM_CLASSES = 2

    def iou(pred, true):
        ious = []
        for c in range(NUM_CLASSES):
            p = (pred == c); t = (true == c)
            inter = (p & t).sum().item(); union = (p | t).sum().item()
            ious.append(inter / union if union > 0 else 1.0)
        return sum(ious) / len(ious)

    def train_seg(model, name, lr, extract=lambda o: o):
        model = model.to(tv_device)
        optim = torch.optim.AdamW(model.parameters(), lr=lr)
        tr_loader = DataLoader(TensorDataset(X_seg_tr, M_seg_tr), batch_size=2, shuffle=True)
        history = []
        for epoch in range(3):
            model.train()
            tr_loss, n = 0.0, 0
            for xb, mb in tr_loader:
                xb, mb = xb.to(tv_device), mb.to(tv_device)
                logits = extract(model(xb))
                loss = F.cross_entropy(logits, mb)
                optim.zero_grad(); loss.backward(); optim.step()
                tr_loss += loss.item() * xb.size(0); n += xb.size(0)
            model.eval()
            with torch.no_grad():
                preds = extract(model(X_seg_val.to(tv_device))).argmax(1).cpu()
                mean_iou = sum(iou(p, t) for p, t in zip(preds, M_seg_val)) / len(M_seg_val)
            history.append({"epoch": epoch+1, "tr_loss": round(tr_loss/n, 4),
                            "mIoU": round(mean_iou, 4)})
            print(f"    [{name}] epoch {epoch+1}: tr_loss={tr_loss/n:.4f}  mIoU={mean_iou:.3f}")
        return {"history": history, "final_mean_iou": history[-1]["mIoU"],
                "n_params_M": round(sum(p.numel() for p in model.parameters())/1e6, 2)}

