                             num_classes=NUM_CLASSES)
        model.aux_classifier = None
        return train_seg(model, "FCN-random", lr=1e-4, extract=lambda o: o["out"])

    class TinyUNet(nn.Module):
        def __init__(self, in_ch=3, n_classes=2, base=16):
            super().__init__()
            def block(ci, co):
                return nn.Sequential(
                    nn.Conv2d(ci, co, 3, padding=1), nn.BatchNorm2d(co), nn.ReLU(inplace=True),
                    nn.Conv2d(co, co, 3, padding=1), nn.BatchNorm2d(co), nn.ReLU(inplace=True))
            self.enc1 = block(in_ch, base)
            self.enc2 = block(base, base*2)
            self.enc3 = block(base*2, base*4)
            self.bot  = block(base*4, base*8)
            self.pool = nn.MaxPool2d(2)
            self.up3  = nn.ConvTranspose2d(base*8, base*4, 2, stride=2)
            self.dec3 = block(base*8, base*4)
            self.up2  = nn.ConvTranspose2d(base*4, base*2, 2, stride=2)
            self.dec2 = block(base*4, base*2)
            self.up1  = nn.ConvTranspose2d(base*2, base, 2, stride=2)
            self.dec1 = block(base*2, base)
            self.head = nn.Conv2d(base, n_classes, 1)
        def forward(self, x):
            e1 = self.enc1(x)
            e2 = self.enc2(self.pool(e1))
            e3 = self.enc3(self.pool(e2))
            b  = self.bot(self.pool(e3))
            d3 = self.dec3(torch.cat([self.up3(b),  e3], dim=1))
            d2 = self.dec2(torch.cat([self.up2(d3), e2], dim=1))
            d1 = self.dec1(torch.cat([self.up1(d2), e1], dim=1))
            return self.head(d1)

    def tv_unet_seg():
        torch.manual_seed(0)
        return train_seg(TinyUNet(3, NUM_CLASSES, base=16), "TinyUNet", lr=1e-3)

