            self.features = nn.Sequential(
                nn.Conv2d(3, 32, 3, padding=1), nn.BatchNorm2d(32), nn.ReLU(inplace=True),
                nn.MaxPool2d(2),
                nn.Conv2d(32, 64, 3, padding=1), nn.BatchNorm2d(64), nn.ReLU(inplace=True),
                nn.MaxPool2d(2),
                nn.Conv2d(64, 128, 3, padding=1), nn.BatchNorm2d(128), nn.ReLU(inplace=True),
                nn.AdaptiveAvgPool2d(1),
            )
            self.classifier = nn.Linear(128, n_classes)
        def forward(self, x):
            return self.classifier(self.features(x).flatten(1))

    def tv_custom_cnn():
        torch.manual_seed(0)
        model = CustomCNN(n_classes=2).to(tv_device)
        optim = torch.optim.AdamW(model.parameters(), lr=1e-3)
        tr_loader = DataLoader(TensorDataset(X_cls_tr_img, y_cls_tr_img), batch_size=4, shuffle=True)
        history = []
        for epoch in range(3):
            model.train()
            loss_sum, n = 0.0, 0
            for xb, yb in tr_loader:
                xb, yb = xb.to(tv_device), yb.to(tv_device)
                loss = F.cross_entropy(model(xb), yb)
                optim.zero_grad(); loss.backward(); optim.step()
                loss_sum += loss.item() * xb.size(0); n += xb.size(0)
            model.eval()
            with torch.no_grad():
                preds = model(X_cls_val_img.to(tv_device)).argmax(1).cpu()
                acc = (preds == y_cls_val_img).float().mean().item()
            history.append({"epoch": epoch+1, "tr_loss": round(loss_sum/n, 4),
                            "val_acc": round(acc, 4)})
            print(f"    [CustomCNN] epoch {epoch+1}: tr_loss={loss_sum/n:.4f}  val_acc={acc:.2f}")
        return {"history": history,
                "final_val_acc": history[-1]["val_acc"],
                "n_params_M": round(sum(p.numel() for p in model.parameters())/1e6, 3)}

    run_test("cv", "torchvision", "custom_cnn_3ep", tv_custom_cnn,
             "кастомная CNN с нуля: 10 train + 10 test, 3 эпохи")
    if tv_device == "cuda": torch.cuda.empty_cache()

    # ---- FGSM на ResNet18 БЕЗ pretrained ----
    # Перед атакой коротко обучаем модель, иначе clean_acc≈adv_acc≈random.
    def tv_fgsm_attack():
        from torchvision.models import resnet18
        torch.manual_seed(0)
        model = resnet18(weights=None)
        model.fc = nn.Linear(model.fc.in_features, 2)
        model = model.to(tv_device)
        x_tr = X_cls_tr_img.to(tv_device); y_tr = y_cls_tr_img.to(tv_device)
        optim = torch.optim.AdamW(model.parameters(), lr=1e-3)
        for _ in range(3):
            model.train()
            optim.zero_grad()
            F.cross_entropy(model(x_tr), y_tr).backward()
            optim.step()
        model.eval()
        x_val = X_cls_val_img.to(tv_device); y_val = y_cls_val_img.to(tv_device)
        with torch.no_grad():
            clean_acc = (model(x_val).argmax(1) == y_val).float().mean().item()
        eps = 0.03
        x_adv = x_val.clone().detach().requires_grad_(True)
        loss = F.cross_entropy(model(x_adv), y_val)
        loss.backward()
        x_adv_final = (x_adv + eps * x_adv.grad.sign()).detach()
        with torch.no_grad():
            adv_acc = (model(x_adv_final).argmax(1) == y_val).float().mean().item()
        perturbation = (x_adv_final - x_val).abs().mean().item()
        return {"eps": eps,
                "clean_acc": round(clean_acc, 4),
                "adv_acc": round(adv_acc, 4),
                "acc_drop": round(clean_acc - adv_acc, 4),
                "mean_perturbation": round(perturbation, 4)}

    run_test("cv", "torchvision", "fgsm_attack", tv_fgsm_attack,
             "FGSM на ResNet18 random init (обучение 3 эпохи + атака)")
    if tv_device == "cuda": torch.cuda.empty_cache()

except ImportError as e:
    fail(f"torchvision: {e}")


