# --------- transformers: USER2-small architecture, random init ---------
subsection("transformers: ModernBERT-small (random init, аналог USER2)")
try:
    import torch
    import torch.nn.functional as F
    from torch.optim import AdamW

    t_device = "cuda" if torch.cuda.is_available() else "cpu"
    _u2 = {"model": None}

    # Простой ручной токенайзер: hash слов в индексы
    VOCAB_SIZE = 2048
    MAX_LEN = 32

    def _tokenize(texts):
        input_ids, attn = [], []
        for text in texts:
            words = text.lower().split()[:MAX_LEN-2]
            ids = [1]
            for w in words:
                ids.append(hash(w) % (VOCAB_SIZE - 10) + 10)
            ids.append(2)
            pad_len = MAX_LEN - len(ids)
            attn.append([1]*len(ids) + [0]*pad_len)
            ids += [0]*pad_len
            input_ids.append(ids)
        return {
            "input_ids":      torch.tensor(input_ids, dtype=torch.long, device=t_device),
            "attention_mask": torch.tensor(attn,      dtype=torch.long, device=t_device),
        }

    def u2_load():
        """Создаём пустую ModernBERT того же семейства, что USER2-small."""
        from transformers import ModernBertConfig, ModernBertModel
        cfg = ModernBertConfig(
            vocab_size=VOCAB_SIZE,
            hidden_size=256,
            num_hidden_layers=4,
            num_attention_heads=4,
            intermediate_size=512,
            max_position_embeddings=MAX_LEN * 2,
            # Явно фиксируем спец-токены В ПРЕДЕЛАХ нашего vocab=2048,
            # иначе ModernBertConfig использует дефолтные id (>50000) и валится с
            # AssertionError: Padding_idx must be within num_embeddings.
            pad_token_id=0,
            bos_token_id=1,
            eos_token_id=2,
            cls_token_id=1,
            sep_token_id=2,
        )
        model = ModernBertModel(cfg).to(t_device)
        _u2["model"] = model
        return {"arch": "ModernBertModel (random init)",
                "params_M": round(sum(p.numel() for p in model.parameters())/1e6, 2),
                "hidden_size": cfg.hidden_size,
                "device": t_device}

    def _mean_pool(h, m):
        mm = m.unsqueeze(-1).float()
        return (h * mm).sum(1) / mm.sum(1).clamp(min=1e-9)

    def _encode(texts, prefix):
        enc = _tokenize([f"{prefix}{t}" for t in texts])
        out = _u2["model"](**enc)
        return F.normalize(_mean_pool(out.last_hidden_state, enc["attention_mask"]), p=2, dim=1)

    VAL_QUERY = "столица нашей страны"
    VAL_DOCS = [
        "Москва является столицей России.",
        "Париж расположен во Франции.",
        "Python — язык программирования.",
        "В Солнечной системе восемь планет.",
        "Кошки любят спать днём.",
    ]

    def u2_infer_before():
        _u2["model"].eval()
        with torch.no_grad():
            q = _encode([VAL_QUERY], "search_query: ")
            d = _encode(VAL_DOCS, "search_document: ")
            sims = (q @ d.T).squeeze(0).cpu().tolist()
        top1 = max(range(len(VAL_DOCS)), key=lambda i: sims[i])
        return {"sims": [round(s, 4) for s in sims], "top1": VAL_DOCS[top1]}

    def u2_finetune():
        pairs = [
            ("столица России", "Москва — столица Российской Федерации."),
            ("столица Франции", "Париж — главный город Франции."),
            ("кто написал Войну и мир", "Роман написан Львом Толстым."),
            ("высокая гора", "Эверест — высочайшая вершина Земли."),
            ("открыл тяготение", "Исаак Ньютон открыл закон всемирного тяготения."),
            ("что такое ДНК", "ДНК несёт генетическую информацию."),
            ("сколько планет", "В Солнечной системе восемь планет."),
            ("большой океан", "Тихий океан — самый большой."),
            ("конец войны", "Вторая мировая война закончилась в 1945 году."),
            ("нарисовал Мону Лизу", "Леонардо да Винчи — автор Моны Лизы."),
        ]
        optim = AdamW(_u2["model"].parameters(), lr=2e-4)
        _u2["model"].train()
        losses = []
        for epoch in range(3):
            ep, nb = 0.0, 0
            for i in range(0, len(pairs), 4):
                batch = pairs[i:i+4]
                if len(batch) < 2: continue
                qs = [p[0] for p in batch]; ds = [p[1] for p in batch]
                q_emb = _encode(qs, "search_query: ")
                d_emb = _encode(ds, "search_document: ")
                scores = q_emb @ d_emb.T * 20.0
                labels = torch.arange(scores.size(0), device=t_device)
                loss = F.cross_entropy(scores, labels)
                optim.zero_grad(); loss.backward(); optim.step()
                ep += loss.item(); nb += 1
            losses.append(ep/nb)
            print(f"    [USER2-random] epoch {epoch+1}: loss={ep/nb:.4f}")
        return {"losses_per_epoch": [round(l, 4) for l in losses]}

    def u2_infer_after():
        _u2["model"].eval()
        with torch.no_grad():
            q = _encode([VAL_QUERY], "search_query: ")
            d = _encode(VAL_DOCS, "search_document: ")
            sims = (q @ d.T).squeeze(0).cpu().tolist()
        top1 = max(range(len(VAL_DOCS)), key=lambda i: sims[i])
        return {"sims": [round(s, 4) for s in sims], "top1": VAL_DOCS[top1]}

    run_test("nlp", "transformers", "user2_load",         u2_load,
             "пустая ModernBERT-small (архитектура USER2, random init)")
    run_test("nlp", "transformers", "user2_infer_before", u2_infer_before,
             "инференс ДО обучения (sims случайные)")
    run_test("nlp", "transformers", "user2_finetune_3ep", u2_finetune,
             "contrastive MNR fine-tune: 10 пар, 3 эпохи")
    run_test("nlp", "transformers", "user2_infer_after",  u2_infer_after,
             "инференс ПОСЛЕ обучения (ждём убывания loss)")

    if t_device == "cuda": torch.cuda.empty_cache()
except ImportError as e:
    fail(f"transformers/torch: {e}")


