try:
    import fasttext

    def fasttext_train_unsupervised():
        corpus_path = "/tmp/_ft_corpus.txt"
        with open(corpus_path, "w", encoding="utf-8") as f:
            for line in [
                "кошка спит на диване",
                "собака лает на кошку",
                "кот любит рыбу и молоко",
                "пёс ест мясо и кость",
                "кошка мурлычет на коленях",
                "собака гуляет в парке каждый день",
                "кот ловит мышь быстро",
                "пёс виляет хвостом от радости",
                "собака охраняет дом ночью",
                "кошка пьёт молоко утром",
            ]:
                f.write(line + "\n")
        model = fasttext.train_unsupervised(
            corpus_path, model="skipgram", dim=50, epoch=10, minCount=1, verbose=0,
        )
        vec_known = model.get_word_vector("кошка")
        vec_oov = model.get_word_vector("кошечка")
        similar = model.get_nearest_neighbors("кошка", k=3)
        return {"vocab_size": len(model.get_words()),
                "dim": int(vec_known.shape[0]),
                "oov_vector_built": bool(vec_oov.any()),
                "top3_neighbors": [(round(float(s), 3), w) for s, w in similar]}

    def fasttext_classification():
        train_path = "/tmp/_ft_train.txt"
        with open(train_path, "w", encoding="utf-8") as f:
            for l in [
                "__label__animal кошка спит на диване",
                "__label__animal собака лает громко",
                "__label__animal кот ловит мышь",
                "__label__animal пёс виляет хвостом",
                "__label__animal кошка пьёт молоко",
                "__label__tech python это язык программирования",
                "__label__tech нейросети обучают на данных",
                "__label__tech компьютер работает быстро",
                "__label__tech алгоритм сортирует массив",
                "__label__tech базы данных хранят информацию",
            ]:
                f.write(l + "\n")
        model = fasttext.train_supervised(
            train_path, epoch=20, lr=0.5, wordNgrams=2, verbose=0, minCount=1,
