# --------- Qwen: маленькая случайная Qwen2 (БЕЗ pretrained) ---------
subsection("Qwen2 — генерация текста (маленькая random init)")
try:
    import torch
    from transformers import Qwen2Config, Qwen2ForCausalLM

    _qwen = {"model": None}
    Q_VOCAB = 2048
    Q_MAXLEN = 64

    def _qwen_tokenize(text):
        words = text.lower().split()[:Q_MAXLEN-1]
        ids = [hash(w) % (Q_VOCAB - 10) + 10 for w in words]
        return ids

    def qwen_load():
        """Маленькая случайная Qwen2 — проверяем что архитектура строится и .generate() работает."""
        cfg = Qwen2Config(
            vocab_size=Q_VOCAB,
            hidden_size=128,
            num_hidden_layers=2,
            num_attention_heads=4,
            num_key_value_heads=2,
            intermediate_size=256,
            max_position_embeddings=Q_MAXLEN * 2,
        )
        device = "cuda" if torch.cuda.is_available() else "cpu"
        model = Qwen2ForCausalLM(cfg).to(device).eval()
        _qwen["model"] = model
        _qwen["device"] = device
        return {"arch": "Qwen2ForCausalLM (random init)",
                "params_M": round(sum(p.numel() for p in model.parameters())/1e6, 2),
                "hidden_size": cfg.hidden_size,
                "device": device}

    def qwen_generate_10_to_3():
        """Из ~10 токенов входа генерируем минимум 3 новых."""
        model = _qwen["model"]; device = _qwen["device"]
        if model is None: raise RuntimeError("Qwen не создан")
        prompt_ids = _qwen_tokenize("столица россии это город москва не петербург")[:10]
        ids = torch.tensor([prompt_ids], dtype=torch.long, device=device)
        n_input = ids.shape[1]
        with torch.no_grad():
            out = model.generate(
                ids,
                max_new_tokens=8,
                min_new_tokens=3,
                do_sample=False,
                pad_token_id=0,
            )
        n_new = int(out.shape[1] - n_input)
        return {"n_input_tokens": n_input,
                "n_generated_tokens": n_new,
                "generated_ids": out[0, n_input:].cpu().tolist()}

    run_test("nlp", "qwen", "load_qwen2_random", qwen_load,
             "маленькая Qwen2ForCausalLM random init (~1M params)")
    run_test("nlp", "qwen", "generate_text",     qwen_generate_10_to_3,
             "генерация: 10 токенов входа → +3 новых")

    del _qwen["model"]; _qwen["model"] = None
    if torch.cuda.is_available(): torch.cuda.empty_cache()
except Exception as e:
    fail(f"Qwen: {type(e).__name__}: {e}")


