# --------- librosa ---------
subsection("librosa")
try:
    import numpy as np
    import librosa

    AUDIO_PATH = "/tmp/_audio_test.wav"

    def _prepare_wav():
        from scipy.io import wavfile
        sr = 16000
        duration = 2.0
        t = np.linspace(0, duration, int(sr * duration), endpoint=False)
        sine = 0.3 * np.sin(2 * np.pi * 440 * t)
        noise = 0.05 * RNG.randn(len(t))
        signal = (sine + noise).astype(np.float32)
        signal_int16 = (signal * 32767).astype(np.int16)
        wavfile.write(AUDIO_PATH, sr, signal_int16)

    _prepare_wav()
    print(f"  подготовлен тестовый wav: {AUDIO_PATH}")

    def audio_load():
        y, sr = librosa.load(AUDIO_PATH, sr=None)
        return {"shape": list(y.shape), "sr": int(sr),
                "max_abs": round(float(np.abs(y).max()), 4)}

    def audio_resample_on_load():
        y8k, sr = librosa.load(AUDIO_PATH, sr=8000)
        return {"shape": list(y8k.shape), "sr_resampled": int(sr)}

    def audio_features():
        y, sr = librosa.load(AUDIO_PATH, sr=None)
        mfcc = librosa.feature.mfcc(y=y, sr=sr, n_mfcc=13)
        mel  = librosa.feature.melspectrogram(y=y, sr=sr, n_mels=64)
        chroma = librosa.feature.chroma_stft(y=y, sr=sr)
        centroid = librosa.feature.spectral_centroid(y=y, sr=sr)
        return {"mfcc_shape": list(mfcc.shape),
                "mel_shape": list(mel.shape),
                "chroma_shape": list(chroma.shape),
                "centroid_mean_hz": round(float(centroid.mean()), 1)}

    def audio_stft_and_pitch():
        y, sr = librosa.load(AUDIO_PATH, sr=None)
        D = librosa.stft(y, n_fft=1024)
        magnitude = np.abs(D)
        freqs = librosa.fft_frequencies(sr=sr, n_fft=1024)
        dominant_freq = freqs[magnitude.mean(axis=1).argmax()]
        return {"stft_shape": list(D.shape),
                "dominant_freq_hz": round(float(dominant_freq), 1)}

    run_test("audio", "librosa", "load",          audio_load,            "чтение WAV через librosa.load")
    run_test("audio", "librosa", "load_resample", audio_resample_on_load, "ресемплинг 16kHz → 8kHz")
    run_test("audio", "librosa", "features",      audio_features,        "MFCC + mel + chroma + centroid")
    run_test("audio", "librosa", "stft_pitch",    audio_stft_and_pitch,  "STFT + доминирующая частота")
except ImportError as e:
    fail(f"librosa не установлен: {e}")


# --------- HuBERT random init ---------
subsection("HuBERT (random init)")
try:
    import torch
    from transformers import HubertConfig, HubertModel

    def hubert_inference():
        """Маленький случайный HuBERT — проверяем что forward проходит на сыром аудио."""
        device = "cuda" if torch.cuda.is_available() else "cpu"
        cfg = HubertConfig(
            hidden_size=128,
            num_hidden_layers=2,
            num_attention_heads=4,
            intermediate_size=256,
        )
        model = HubertModel(cfg).to(device).eval()
        # Сырой аудиосигнал из librosa: одномерный тензор float32 в диапазоне ~[-1,1]
        import librosa
        y, sr = librosa.load("/tmp/_audio_test.wav", sr=16000)
        x = torch.tensor(y, dtype=torch.float32, device=device).unsqueeze(0)
        with torch.no_grad():
            out = model(x)
        hidden = out.last_hidden_state
        utt_emb = hidden.mean(dim=1)
        n_params = sum(p.numel() for p in model.parameters())
        result = {
            "arch": "HubertModel (random init)",
            "params_M": round(n_params/1e6, 2),
            "input_sr": 16000,
            "frames_out": int(hidden.shape[1]),
            "hidden_dim": int(hidden.shape[2]),
            "utterance_emb_shape": list(utt_emb.shape),
        }
        del model
        if torch.cuda.is_available(): torch.cuda.empty_cache()
        return result

    run_test("audio", "transformers", "hubert_inference", hubert_inference,
             "маленький HubertModel random init: forward на сыром wav")
except Exception as e:
    fail(f"HuBERT: {type(e).__name__}: {e}")


