def print_task_report(task_id):
    task = TASKS.get(task_id)
    if not task: return
    print("\n" + "-" * 72)
    print(f"  Отчёт по задаче {task_id}: {task['title']}")
    print("-" * 72)
    total_ok, total_fail, total_missing = 0, 0, 0
    for block, lib, test_names in task["uses"]:
        ver = results["env"]["versions"].get(lib, "?")
        ver_str = f"v{ver}" if ver and ver != "?" else "n/a"
        lib_tests = []
        for tname in test_names:
            t = get_test(block, lib, tname)
            if t is None:
                lib_tests.append((tname, "missing", None, ""))
                total_missing += 1
            elif t["status"] == "ok":
                lib_tests.append((tname, "ok", t, t.get("description", "")))
                total_ok += 1
            else:
                lib_tests.append((tname, "fail", t, t.get("description", "")))
                total_fail += 1
        n_ok = sum(1 for x in lib_tests if x[1] == "ok")
        n_fail = sum(1 for x in lib_tests if x[1] == "fail")
        n_miss = sum(1 for x in lib_tests if x[1] == "missing")
        extra = []
        if n_ok:   extra.append(f"{n_ok} ok")
        if n_fail: extra.append(f"{n_fail} fail")
        if n_miss: extra.append(f"{n_miss} missing")
        print(f"\n  • [{block}] {lib}  ({ver_str})  —  {' / '.join(extra)}")
        for tname, status, t, desc in lib_tests:
            mark = {"ok": "✓", "fail": "✗", "missing": "?"}[status]
            print(f"      {mark} {tname:<24} — {desc}")
            if status == "fail":
                print(f"         └─ {t.get('error', '')}")
    print(f"\n  Итого: {total_ok} ok / {total_fail} fail / {total_missing} missing")


# ====================================================================
section("Отчёты по задачам")
for tid in sorted(TASKS.keys()):
    print_task_report(tid)


# ====================================================================
print()
with open("ml_env_check.json", "w") as f:
    json.dump(results, f, indent=2, ensure_ascii=False, default=str)
print("Полные результаты: ml_env_check.json")
